const { AxiosError } = require('axios');

const { logger } = require('../logger');
const { statsd } = require('./statsd');

/**
 * Sends a metric to nordic dashboard and throws an error if content-type header is application/json
 * Related to https://github.com/axios/axios/pull/2849 and https://github.com/axios/axios/pull/2856
 * @param {Error} error json error
 * @param {Object} headers response headers
 * @param {Object} config configuration object
 * @param {Object} data response payload
 * @throws Throws if header content-type starts with 'application/json'
 */
function throwIfJsonExpected(error, headers, config, data) {
  const contentType = headers?.['content-type'] || '';

  if (!data || !contentType.startsWith('application/json')) {
    return;
  }

  const message = `Response content-type is "${contentType}" for URL "${config.url}" but there was an error parsing JSON: "${error.name} ${error.message}"`;

  statsd.increment('nordic.frontend_axios.error_parsing_json', 1, {
    instance_id: process.env.INSTANCE_ID,
  });
  logger.warn('nordic.frontend_axios.error_parsing_json', {
    instance_id: process.env.INSTANCE_ID,
    url: config.url,
  });

  const err = new AxiosError(message, AxiosError.ERR_BAD_RESPONSE, config);

  err.cause = error;

  throw err;
}

module.exports = {
  throwIfJsonExpected,
};
